public boolean hasAttr(String attributeKey) {
    Validate.notNull(attributeKey);

    String key = attributeKey;
    if (attributeKey.startsWith("abs:")) {
        key = attributeKey.substring(4);
        String absUrlValue = absUrl(key);
        return attributes.hasKey(key) && absUrlValue != null && !absUrlValue.isEmpty();
    }

    return attributes.hasKey(attributeKey);
}

public boolean hasAttr(String attributeKey) {
    Validate.notNull(attributeKey);

    if (attributeKey.contains(":")) {
        String[] parts = attributeKey.split(":", 2);
        String protocol = parts[0];
        String key = parts[1];
        if (protocol.equals("abs")) {
            return !absUrl(key).isEmpty();
        }
        // Handle other protocols here if necessary
        return false;
    }
    return attributes.hasKey(attributeKey);
}

public boolean hasAttr(String attributeKey) {
    Validate.notNull(attributeKey);

    if (attributeKey.contains(":")) {
        String[] parts = attributeKey.split(":");
        String baseKey = parts[parts.length - 1];
        return attributes.hasKey(baseKey) && !absUrl(baseKey).isEmpty();
    } else {
        return attributes.hasKey(attributeKey);
    }
}
